import { Platform } from 'react-native';

const API_URL = 'https://api.example.com';
const API_KEY = 'your_api_key_here'; // replace with your actual api key

function getHeaders() {
  return {
    Accept: 'application/json',
    'Content-Type': 'application/json',
    Authorization: `Bearer ${API_KEY}`,
  };
}

async function fetchUserProfile(id) {
  try {
    const response = await fetch(`${API_URL}/users/${id}`, { headers: getHeaders() });
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return response.json();
  } catch (error) {
    console.error('Error fetching user profile:', error);
    throw error;
  }
}

async function updateUserData(id, data) {
  try {
    const response = await fetch(`${API_URL}/users/${id}`, {
      method: 'PATCH',
      headers: { ...getHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return response.json();
  } catch (error) {
    console.error('Error updating user data:', error);
    throw error;
  }
}

async function fetchUserList() {
  try {
    const response = await fetch(`${API_URL}/users`, { headers: getHeaders() });
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return response.json();
  } catch (error) {
    console.error('Error fetching user list:', error);
    throw error;
  }
}

// Example usage:
fetchUserProfile(1)
  .then((userProfile) => console.log(userProfile))
  .catch((error) => console.error(error));

updateUserData(1, { name: 'John Doe', email: 'john@example.com' })
  .then((updatedData) => console.log(updatedData))
  .catch((error) => console.error(error));

fetchUserList()
  .then((userList) => console.log(userList))
  .catch((error) => console.error(error));